import React, { useContext, useEffect, useState } from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, View } from 'react-native';
import { AuthContext } from '../../App';
import { useNavigation } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { RootStackParamList } from '../navigation/AppNavigator';
import TopNav from '../components/TopNav';
import OwnerBottomNav from '../components/OwnerBottomNav';
import { fetchOwnerOrders, OrderRecord, updateOrderStatus } from '../services/firebaseService';

const OwnerHomeScreen = () => {
  const { profile } = useContext(AuthContext);
  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
  const [orders, setOrders] = useState<OrderRecord[]>([]);
  const [filter, setFilter] = useState<'Today' | 'This week' | 'Month' | 'Year'>('This week');
  const [menuOpenFor, setMenuOpenFor] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const loadOrders = async () => {
      try {
        const data = await fetchOwnerOrders();
        setOrders(data);
      } catch {
        setOrders([]);
      }
    };
    loadOrders();
  }, []);

  const handleStatusSelect = async (orderId: string, status: OrderRecord['status']) => {
    setSaving(true);
    try {
      await updateOrderStatus(orderId, status);
      setOrders((prev) =>
        prev.map((order) => (order.id === orderId ? { ...order, status } : order))
      );
    } finally {
      setSaving(false);
      setMenuOpenFor(null);
    }
  };

  const now = new Date();
  const filterStart = (() => {
    const d = new Date(now);
    switch (filter) {
      case 'Today':
        d.setHours(0, 0, 0, 0);
        return d;
      case 'This week': {
        const day = d.getDay();
        const diff = (day + 6) % 7;
        d.setDate(d.getDate() - diff);
        d.setHours(0, 0, 0, 0);
        return d;
      }
      case 'Month':
        return new Date(d.getFullYear(), d.getMonth(), 1);
      case 'Year':
        return new Date(d.getFullYear(), 0, 1);
      default:
        return d;
    }
  })();

  const filteredOrders = orders.filter((order) => new Date(order.createdAt) >= filterStart);

  const totalOrders = filteredOrders.length;
  const pendingDeliveries = filteredOrders.filter((order) => order.status !== 'delivered').length;
  const orderNumber = (order?: OrderRecord) => {
    if (order?.orderNumber) return String(order.orderNumber).padStart(5, '0');
    return '00000';
  };
  const statusStyle = (status: OrderRecord['status']) => {
    switch (status) {
      case 'pending':
        return { bg: '#FEF3C7', text: '#B45309' };
      case 'confirmed':
        return { bg: '#DBEAFE', text: '#1D4ED8' };
      case 'preparing':
        return { bg: '#EDE9FE', text: '#6D28D9' };
      case 'out_for_delivery':
        return { bg: '#D1FAE5', text: '#047857' };
      case 'delivered':
        return { bg: '#DCFCE7', text: '#15803D' };
      case 'cancelled':
        return { bg: '#FEE2E2', text: '#B91C1C' };
      default:
        return { bg: '#E5E7EB', text: '#374151' };
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <TopNav />
      <View style={styles.body}>
        <ScrollView contentContainerStyle={styles.content} style={styles.scroll}>
        <View style={styles.topRow}>
          <Text style={styles.heading}>Owner dashboard</Text>
          <Pressable style={styles.profileButton} onPress={() => navigation.navigate('Profile')}>
            <Text style={styles.profileButtonText}>Profile</Text>
          </Pressable>
        </View>
        <View style={styles.filterRow}>
          {(['Today', 'This week', 'Month', 'Year'] as const).map((label) => (
            <Pressable
              key={label}
              style={[styles.filterChip, label === filter && styles.filterChipActive]}
              onPress={() => setFilter(label)}
            >
              <Text style={[styles.filterText, label === filter && styles.filterTextActive]}>{label}</Text>
            </Pressable>
          ))}
        </View>
        <View style={styles.statsRow}>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Orders</Text>
            <Text style={styles.statValue}>
              {totalOrders} ({filteredOrders.reduce((sum, o) => sum + o.quantity, 0)})
            </Text>
          </Pressable>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Delivered</Text>
            <Text style={styles.statValue}>
              {filteredOrders.filter((o) => o.status === 'delivered').length} (
              {filteredOrders.filter((o) => o.status === 'delivered').reduce((sum, o) => sum + o.quantity, 0)})
            </Text>
          </Pressable>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Pending</Text>
            <Text style={styles.statValue}>
              {filteredOrders.filter((o) => o.status !== 'delivered').length} (
              {filteredOrders.filter((o) => o.status !== 'delivered').reduce((sum, o) => sum + o.quantity, 0)})
            </Text>
          </Pressable>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Total</Text>
            <Text style={styles.statValue}>₹{filteredOrders.reduce((sum, o) => sum + o.quantity * 20, 0)}</Text>
          </Pressable>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Received</Text>
            <Text style={styles.statValue}>₹{filteredOrders.reduce((sum, o) => sum + (o.paidAmount ?? 0), 0)}</Text>
          </Pressable>
          <Pressable style={styles.statCard} onPress={() => navigation.navigate('OwnerOrders')}>
            <Text style={styles.statLabel}>Pending</Text>
            <Text style={styles.statValue}>
              ₹{Math.max(filteredOrders.reduce((sum, o) => sum + o.quantity * 20, 0) - filteredOrders.reduce((sum, o) => sum + (o.paidAmount ?? 0), 0), 0)}
            </Text>
          </Pressable>
        </View>
        <View style={styles.card}>
          <Text style={styles.cardTitle}>Recent orders</Text>
          {filteredOrders.slice(0, 4).map((order) => (
            <Pressable
              key={order.id}
              style={styles.orderRow}
              onPress={() => navigation.navigate('OrderDetails', { orderId: order.id! })}
            >
              <View>
                <Text style={styles.orderPrimary}>#{orderNumber(order)} • {order.customerName}</Text>
                <Text style={styles.orderSecondary}>{order.quantity} cans • {order.paymentMethod}</Text>
              </View>
              <View style={styles.statusMenu}>
                {(() => {
                  const style = statusStyle(order.status);
                  return (
                <Pressable
                  style={[styles.statusChip, { backgroundColor: style.bg }]}
                  onPress={() => setMenuOpenFor(menuOpenFor === order.id ? null : order.id!)}
                  disabled={saving}
                >
                  <Text style={[styles.orderStatus, { color: style.text }]}>{order.status.toUpperCase()}</Text>
                </Pressable>
                  );
                })()}
                {menuOpenFor === order.id ? (
                  <View style={styles.statusDropdown}>
                    {(['pending', 'confirmed', 'preparing', 'out_for_delivery', 'delivered', 'cancelled'] as Array<OrderRecord['status']>).map(
                      (status) => {
                        const style = statusStyle(status);
                        return (
                          <Pressable
                            key={status}
                            style={styles.statusOption}
                            onPress={() => handleStatusSelect(order.id!, status)}
                          >
                            <Text style={[styles.statusOptionText, { color: style.text }]}>{status.toUpperCase()}</Text>
                          </Pressable>
                        );
                      }
                    )}
                  </View>
                ) : null}
              </View>
            </Pressable>
          ))}
          {orders.length === 0 ? (
            <Text style={styles.emptyText}>No orders yet.</Text>
          ) : null}
        </View>
        <View style={styles.card}>
          <Text style={styles.cardTitle}>Approve customers</Text>
          <Text style={styles.cardText}>Review new signups and approve phone numbers to enable ordering.</Text>
          <Pressable style={styles.button} onPress={() => navigation.navigate('OwnerApprovals')}>
            <Text style={styles.buttonText}>Approve customers</Text>
          </Pressable>
        </View>
        </ScrollView>
        <OwnerBottomNav active="OwnerHome" />
      </View>
    </SafeAreaView>
  );
};

